import "./HomePage.css";
import Main from "../../Components/Main/Main";
import Home from "../../Components/Home/Home";
import React, { useEffect } from "react";
import { cars } from "../../Components/SliderImages";

function HomePage() {
  useEffect(() => {
    Aos.init({ duration: 2000 });
    window.scrollTo(0, 0);
  }, []);
  return (
    <>
      <Home />
      <Main images={cars} />
    </>
  );
}

export default HomePage;
